  1	import {
  2	  Button,
  3	  Divider,
  4	  EmptyState,
  5	  EmptyStateBody,
  6	  EmptyStateHeader,
  7	  EmptyStateIcon,
  8	  EmptyStateVariant,
  9	  ExpandableSection,
 10	  ExpandableSectionToggle,
 11	  Flex,
 12	  Spinner,
 13	  Stack,
 14	  StackItem,
 15	  Tooltip,
 16	} from '@patternfly/react-core';
 17	import {
 18	  CubesIcon,
 19	  ExclamationCircleIcon,
 20	  LinkIcon,
 21	  SlidersHIcon,
 22	  SyncIcon,
 23	  UnlinkIcon,
 24	} from '@patternfly/react-icons';
 25	import * as React from 'react';
 26	import { TFunction, useTranslation } from 'react-i18next';
 27	import { useDispatch, useSelector } from 'react-redux';
 28	import { useLocationQuery } from '../hooks/useLocationQuery';
 29	import { usePluginAvailable } from '../hooks/usePluginAvailable';
 30	import { getGoalsGraph, getNeighborsGraph } from '../korrel8r-client';
 31	import * as api from '../korrel8r/client';
 32	import * as korrel8r from '../korrel8r/types';
 33	import { defaultSearch, Result, Search, SearchType, setResult, setSearch } from '../redux-actions';
 34	import { State } from '../redux-reducers';
 35	import * as time from '../time';
 36	import { AdvancedSearchForm } from './AdvancedSearchForm';
 37	import './korrel8rpanel.css';
 38	import { TimeRangeDropdown } from './TimeRangeDropdown';
 39	import { Korrel8rTopology } from './topology/Korrel8rTopology';
 40	
 41	export default function Korrel8rPanel() {
 42	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
 43	  const dispatch = useDispatch();
 44	  const locationQuery = useLocationQuery();
 45	
 46	  const search: Search = useSelector((state: State) => state.plugins?.tp?.get('search'));
 47	  const result: Result | null = useSelector((state: State) => state.plugins?.tp?.get('result'));
 48	
 49	  // Is the search panel already in focus on the main view?
 50	  const isFocused = React.useMemo(
 51	    () => locationQuery?.toString() === search.queryStr,
 52	    [locationQuery, search.queryStr],
 53	  );
 54	
 55	  // Showing advanced query
 56	  const [showAdvanced, setShowAdvanced] = React.useState(false);
 57	
 58	  // Compute constraint from period for the API call and topology navigation.
 59	  const constraint = React.useMemo((): korrel8r.Constraint | undefined => {
 60	    if (!search.period) return undefined;
 61	    const [pStart, pEnd] = search.period.startEnd();
 62	    return new korrel8r.Constraint({ start: pStart, end: pEnd });
 63	  }, [search.period]);
 64	
 65	  const initialized = React.useRef(false);
 66	  React.useEffect(() => {
 67	    if (initialized.current) return; // Run once on mount
 68	    initialized.current = true;
 69	    if (!search?.queryStr && locationQuery) {
 70	      dispatch(setSearch({ ...defaultSearch, queryStr: locationQuery.toString() }));
 71	    }
 72	  }, [search?.queryStr, locationQuery, dispatch]);
 73	
 74	  React.useEffect(() => {
 75	    // Leave stored result in place if there is one.
 76	    // Dispatching SetSearch clears result to null, triggering a new fetch.
 77	    if (result) return;
 78	
 79	    const queryStr = search?.queryStr?.trim();
 80	    const start: api.Start = {
 81	      queries: queryStr ? [queryStr] : undefined,
 82	      constraint: constraint?.toAPI(),
 83	    };
 84	    let cancelled = false;
 85	    const onResult = (newResult: Result) => {
 86	      if (!cancelled) dispatch(setResult(newResult));
 87	    };
 88	    const fetch =
 89	      search.searchType === SearchType.Goal
 90	        ? getGoalsGraph({ start, goals: [search.goal] })
 91	        : getNeighborsGraph({ start, depth: search.depth });
 92	    fetch
 93	      .then((response: api.Graph) => onResult({ graph: new korrel8r.Graph(response) }))
 94	      .catch((e: api.ApiError) => {
 95	        onResult({
 96	          title: e?.body?.error ? t('Korrel8r Error') : t('Request Failed'),
 97	          message: e?.body?.error || e.message || 'Unknown Error',
 98	        });
 99	      });
100	    return () => {
101	      cancelled = true;
102	      fetch.cancel();
103	    };
104	  }, [search, t, result, constraint, dispatch]);
105	
106	  const advancedToggleID = 'query-toggle';
107	  const advancedContentID = 'query-content';
108	
109	  // Dispatch a new search.
110	  // The SetSearch reducer clears result, triggering the fetch effect.
111	  const doSearch = React.useCallback((s: Search) => dispatch(setSearch(s)), [dispatch]);
112	
113	  return (
114	    <>
115	      <Stack>
116	        <Flex
117	          className="tp-plugin__panel-toolbar"
118	          direction={{ default: 'row' }}
119	          flexWrap={{ default: 'nowrap' }}
120	          alignItems={{ default: 'alignItemsCenter' }}
121	          spaceItems={{ default: 'spaceItemsXs' }}
122	        >
123	          <Tooltip
124	            content={
125	              locationQuery
126	                ? isFocused
127	                  ? t('Correlation graph is focused on the main view.')
128	                  : t('Focus the correlation on the main view.')
129	                : t('Current view does not allow correlation.')
130	            }
131	          >
132	            <Button
133	              className="tp-plugin__compact-control"
134	              isAriaDisabled={!locationQuery || isFocused}
135	              size="sm"
136	              onClick={() => {
137	                doSearch({
138	                  ...defaultSearch,
139	                  queryStr: locationQuery?.toString(),
140	                  period: search?.period,
141	                });
142	              }}
143	              icon={isFocused ? <LinkIcon /> : <UnlinkIcon />}
144	            >
145	              {t('Focus')}
146	            </Button>
147	          </Tooltip>
148	
149	          {/* Time range drop-down */}
150	          <Flex align={{ default: 'alignRight' }} spaceItems={{ default: 'spaceItemsNone' }}>
151	            <Tooltip content={t('Include data from this time range')}>
152	              <TimeRangeDropdown
153	                className="tp-plugin__compact-control"
154	                period={search.period ?? defaultSearch.period}
155	                onChange={(period: time.Period) => doSearch({ ...search, period })}
156	              />
157	            </Tooltip>
158	          </Flex>
159	
160	          {/* Right aligned buttons */}
161	          <Flex align={{ default: 'alignRight' }} spaceItems={{ default: 'spaceItemsNone' }}>
162	            {/* Advanced search toggle */}
163	            <Tooltip content={t('Advanced search parameters')}>
164	              <ExpandableSectionToggle
165	                contentId={advancedContentID}
166	                toggleId={advancedToggleID}
167	                isExpanded={showAdvanced}
168	                onToggle={(on: boolean) => setShowAdvanced(on)}
169	                aria-label={t('Advanced search parameters')}
170	              >
171	                <SlidersHIcon />
172	              </ExpandableSectionToggle>
173	            </Tooltip>
174	
175	            {/* Refresh button */}
176	            <Tooltip content={t('Refresh the graph by re-running the current search.')}>
177	              <Button
178	                variant="link"
179	                size="sm"
180	                isAriaDisabled={!search?.queryStr}
181	                onClick={() => doSearch(search)}
182	                aria-label={t('Refresh')}
183	              >
184	                <SyncIcon />
185	              </Button>
186	            </Tooltip>
187	          </Flex>
188	        </Flex>
189	
190	        <ExpandableSection
191	          className="tp-plugin__panel-query-container"
192	          contentId={advancedContentID}
193	          toggleId={advancedToggleID}
194	          isExpanded={showAdvanced}
195	          isDetached
196	        >
197	          <AdvancedSearchForm
198	            search={search}
199	            onSearch={doSearch}
200	            onCancel={() => setShowAdvanced(false)}
201	          />
202	        </ExpandableSection>
203	
204	        <Divider />
205	
206	        <StackItem className="tp-plugin__panel-topology-container" isFilled={true}>
207	          <Topology result={result} t={t} constraint={constraint} />
208	        </StackItem>
209	      </Stack>
210	    </>
211	  );
212	}
213	
214	interface TopologyProps {
215	  result?: Result;
216	  constraint?: korrel8r.Constraint;
217	  t: TFunction;
218	}
219	
220	const Topology: React.FC<TopologyProps> = ({ result, t, constraint }) => {
221	  const [loggingAvailable, loggingAvailableLoading] = usePluginAvailable('logging-view-plugin');
222	  const [netobserveAvailable, netobserveAvailableLoading] = usePluginAvailable('netobserv-plugin');
223	
224	  if (!result || loggingAvailableLoading || netobserveAvailableLoading) {
225	    // korrel8r query is loading or the plugin checks are loading
226	    return <Searching />;
227	  }
228	
229	  if (result?.graph?.nodes) {
230	    // Non-empty graph
231	    return (
232	      <Korrel8rTopology
233	        graph={result.graph}
234	        loggingAvailable={loggingAvailable}
235	        netobserveAvailable={netobserveAvailable}
236	        constraint={constraint}
237	      />
238	    );
239	  }
240	
241	  return (
242	    <TopologyInfoState
243	      titleText={result.title || t('No Correlated Signals Found')}
244	      // Only display fisrt 400 characters of error to prevent repeating errors
245	      text={result.message ? result.message.slice(0, 400) : t('Correlation result was empty.')}
246	      isError={result.isError}
247	    />
248	  );
249	};
250	
251	const Searching: React.FC = () => {
252	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
253	  return (
254	    <div className="tp-plugin__panel-topology-info">
255	      <EmptyState variant={EmptyStateVariant.sm}>
256	        <EmptyStateHeader
257	          titleText={t('Searching')}
258	          headingLevel="h4"
259	          icon={<EmptyStateIcon icon={Spinner} />}
260	        />
261	      </EmptyState>
262	    </div>
263	  );
264	};
265	
266	interface TopologyInfoStateProps {
267	  titleText: string;
268	  text: string;
269	  isError?: boolean;
270	}
271	
272	const TopologyInfoState: React.FC<TopologyInfoStateProps> = ({ titleText, text, isError }) => {
273	  return (
274	    <div className="tp-plugin__panel-topology-info">
275	      <EmptyState variant={EmptyStateVariant.sm}>
276	        <EmptyStateHeader
277	          titleText={titleText}
278	          headingLevel="h4"
279	          icon={
280	            <EmptyStateIcon
281	              icon={isError ? ExclamationCircleIcon : CubesIcon}
282	              color={isError ? 'var(--pf-t--global--color--status--danger--default)' : ''}
283	            />
284	          }
285	        />
286	        <EmptyStateBody>{text}</EmptyStateBody>
287	      </EmptyState>
288	    </div>
289	  );
290	};

