 40	
 41	const capitalize = (s: string) => (s ? s[0].toUpperCase() + s.slice(1) : '');
 42	
 43	const nodeLabel = (node: korrel8r.Node): string => {
 44	  const c = node.class;
 45	  if (!c) return `[${node.id}]`; // Original un-parsed class name.
 46	  if (c.domain === 'k8s') return c.name.replace(/\..*$/, ''); // Strip group/version
 47	  return capitalize(c.name);
 48	};
 49	
 50	const nodeBadge = (node: korrel8r.Node): string => {
 51	  const queries = nodeQueries(node);
 52	  return `${queries.length > 1 ? `${queries[0]?.count}/` : ''}${node?.count ?? '?'} `;
 53	};
 54	
 55	const nodeQueries = (node: korrel8r.Node) => node?.queries ?? [];
 56	
 57	interface Korrel8rTopologyNodeProps {
 58	  element: Node;
 59	}
 60	
 61	const Korrel8rTopologyNode: React.FC<
 62	  Korrel8rTopologyNodeProps & WithContextMenuProps & WithSelectionProps
 63	> = ({ element, onSelect, selected, onContextMenu, contextMenuOpen }) => {
