 95	export const Korrel8rTopology: React.FC<{
 96	  graph: korrel8r.Graph;
 97	  loggingAvailable: boolean;
 98	  netobserveAvailable: boolean;
 99	  constraint: korrel8r.Constraint;
100	}> = ({ graph, loggingAvailable, netobserveAvailable, constraint }) => {
101	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
102	  const navigateToQuery = useNavigateToQuery();
103	  const [selectedIds, setSelectedIds] = React.useState<string[]>([]);
104	
105	  const nodes = React.useMemo(
106	    () =>
107	      graph.nodes.map((node: korrel8r.Node) => {
108	        if (node.error) {
109	          // eslint-disable-next-line no-console
110	          console.warn(`korrel8r node: ${node.error}`);
111	          node.error = t('Unable to find Console Link');
112	        } else if (node.class.domain === 'log' && !loggingAvailable) {
113	          node.error = t('Logging Plugin Disabled');
114	        } else if (node.class.domain === 'netflow' && !netobserveAvailable) {
115	          node.error = t('Netflow Plugin Disabled');
116	        }
117	        return {
118	          id: node.id,
119	          type: 'node',
120	          width: NODE_DIAMETER,
121	          height: NODE_DIAMETER,
122	          shape: NODE_SHAPE,
123	          data: node,
124	        };
125	      }),
126	    [graph, loggingAvailable, netobserveAvailable, t],
127	  );
128	
129	  const edges = React.useMemo(
130	    () =>
131	      graph.edges.map((edge: korrel8r.Edge) => {
132	        return {
133	          id: `edge:${edge.start.id} -${edge.goal.id} `,
134	          type: 'edge',
135	          source: edge.start.id,
136	          target: edge.goal.id,
137	          edgeStyle: EdgeStyle.default,
138	        };
139	      }),
140	    [graph],
141	  );
142	
143	  const selectionAction = React.useCallback(
144	    (selected: Array<string>) => {
145	      const id = selected?.[0]; // Select only one at a time.
146	      setSelectedIds([id]);
147	      const node = graph.node(id);
148	      if (!node || node.error) return;
149	      navigateToQuery(node.queries?.[0]?.query, constraint);
150	    },
151	    [graph, navigateToQuery, setSelectedIds, constraint],
152	  );
153	
154	  const nodeMenu = React.useCallback(
155	    (e: GraphElement<ElementModel, korrel8r.Node>): React.ReactElement[] => {
156	      const node = e.getData();
157	      const menu = [
158	        <ContextMenuItem isDisabled={true} key={node.class.toString()}>
159	          <Title headingLevel="h4">{node.class.toString()}</Title>
160	        </ContextMenuItem>,
161	      ];
162	      nodeQueries(node).forEach((qc) =>
163	        menu.push(
164	          <ContextMenuItem
165	            key={qc.query.toString()}
166	            onClick={() => {
167	              navigateToQuery(qc.query, constraint);
168	              setSelectedIds([node.id]);
169	              navigator.clipboard.writeText(qc.query.toString());
170	            }}
171	            icon={<Badge>{`${qc.count} `}</Badge>}
172	          >
173	            {`${qc.query.selector} `}
174	          </ContextMenuItem>,
175	        ),
176	      );
177	      return menu;
178	    },
179	    [navigateToQuery, setSelectedIds, constraint],
180	  );
181	
182	  const componentFactory: ComponentFactory = React.useCallback(
183	    (kind: ModelKind, type: string) => {
184	      if (type === 'group') return DefaultGroup;
185	      switch (kind) {
186	        case ModelKind.graph:
187	          return withPanZoom()(GraphComponent);
188	        case ModelKind.node:
189	          return withContextMenu(nodeMenu)(withSelection()(Korrel8rTopologyNode));
190	        case ModelKind.edge:
191	          return DefaultEdge;
192	        default:
193	          return undefined;
194	      }
195	    },
196	    [nodeMenu],
197	  );
198	
199	  const controller = React.useMemo(() => {
200	    const model: Model = {
201	      nodes,
202	      edges,
203	      graph: {
204	        id: 'korrel8r_graph',
205	        type: 'graph',
206	        layout: 'BreadthFirst',
207	      },
208	    };
209	
210	    const controller = new Visualization();
211	    controller.registerLayoutFactory((_, graph: Graph) => new BreadthFirstLayout(graph));
212	    controller.fromModel(model, false);
213	    return controller;
214	  }, [nodes, edges]);
215	
216	  // NOTE: For some reason, the controller function above cannot depend on memoized functions
217	  // like selectionAction or componentfactory. Using a separate memo works. Strange.
218	  // The Visualization below must depend on controller 2.
219	  const controller2 = React.useMemo(() => {
220	    controller.addEventListener(SELECTION_EVENT, selectionAction);
221	    controller.registerComponentFactory(componentFactory);
222	    controller.setFitToScreenOnLayout(true, PADDING);
223	    return controller;
224	  }, [controller, selectionAction, componentFactory]);
225	
226	  const containerRef = React.useRef<HTMLDivElement>(null);
227	  React.useEffect(() => {
228	    const element = containerRef.current;
229	    if (!element) return;
230	    let timer: ReturnType<typeof setTimeout>;
231	    const observer = new ResizeObserver(() => {
232	      clearTimeout(timer);
233	      timer = setTimeout(() => controller.getGraph().fit(PADDING), 150);
234	    });
235	    observer.observe(element);
236	    return () => {
237	      clearTimeout(timer);
238	      observer.disconnect();
239	    };
240	  }, [controller]);
241	
242	  return (
243	    <div ref={containerRef} style={{ width: '100%', height: '100%' }}>
244	      <TopologyView
245	        controlBar={
246	          <TopologyControlBar
247	            controlButtons={createTopologyControlButtons({
248	              ...defaultControlButtonsOptions,
249	              zoomInCallback: action(() => {
250	                controller.getGraph().scaleBy(4 / 3);
251	              }),
252	              zoomOutCallback: action(() => {
253	                controller.getGraph().scaleBy(0.75);
254	              }),
255	              fitToScreen: false, // Same thing as resetView
256	              resetViewCallback: action(() => {
257	                controller.getGraph().reset();
258	                controller.getGraph().layout();
259	              }),
260	              legend: false,
261	            })}
262	          />
263	        }
264	      >
265	        <VisualizationProvider controller={controller2}>
266	          <VisualizationSurface state={{ selectedIds }} />
267	        </VisualizationProvider>
268	      </TopologyView>
269	    </div>
270	  );
271	};

