 16	  CubesIcon,
 17	  ExclamationCircleIcon,
 18	  LinkIcon,
 19	  SlidersHIcon,
 20	  SyncIcon,
 21	  UnlinkIcon,
 22	} from '@patternfly/react-icons';
 23	import * as React from 'react';
 24	import { TFunction, useTranslation } from 'react-i18next';
 25	import { useDispatch, useSelector } from 'react-redux';
 26	import { useLocationQuery } from '../hooks/useLocationQuery';
 27	import { usePluginAvailable } from '../hooks/usePluginAvailable';
 28	import { getGoalsGraph, getNeighborsGraph } from '../korrel8r-client';
 29	import * as api from '../korrel8r/client';
 30	import * as korrel8r from '../korrel8r/types';
 31	import { defaultSearch, Result, Search, SearchType, setResult, setSearch } from '../redux-actions';
 32	import { State } from '../redux-reducers';
 33	import * as time from '../time';
 34	import { AdvancedSearchForm } from './AdvancedSearchForm';
 35	import './korrel8rpanel.css';
 36	import { TimeRangeDropdown } from './TimeRangeDropdown';
 37	import { Korrel8rTopology } from './topology/Korrel8rTopology';
 38	
 39	export default function Korrel8rPanel() {
 40	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
 41	  const dispatch = useDispatch();
 42	  const locationQuery = useLocationQuery();
 43	
 44	  const search: Search = useSelector((state: State) => state.plugins?.tp?.get('search'));
 45	  const result: Result | null = useSelector((state: State) => state.plugins?.tp?.get('result'));
 46	
 47	  // Is the search panel already in focus on the main view?
 48	  const isFocused = React.useMemo(
 49	    () => locationQuery?.toString() === search.queryStr,
 50	    [locationQuery, search.queryStr],
 51	  );
 52	
 53	  // Showing advanced query
 54	  const [showAdvanced, setShowAdvanced] = React.useState(false);
 55	
 56	  // Compute constraint from period for the API call and topology navigation.
 57	  const constraint = React.useMemo((): korrel8r.Constraint | undefined => {
 58	    if (!search.period) return undefined;
 59	    const [pStart, pEnd] = search.period.startEnd();
 60	    return new korrel8r.Constraint({ start: pStart, end: pEnd });
 61	  }, [search.period]);
 62	
 63	  const initialized = React.useRef(false);
 64	  React.useEffect(() => {
 65	    if (initialized.current) return; // Run once on mount
 66	    initialized.current = true;
 67	    if (!search?.queryStr && locationQuery) {
 68	      dispatch(setSearch({ ...defaultSearch, queryStr: locationQuery.toString() }));
 69	    }
 70	  }, [search?.queryStr, locationQuery, dispatch]);
 71	
 72	  React.useEffect(() => {
 73	    // Leave stored result in place if there is one.
 74	    // Dispatching SetSearch clears result to null, triggering a new fetch.
 75	    if (result) return;
 76	
 77	    const queryStr = search?.queryStr?.trim();
 78	    const start: api.Start = {
 79	      queries: queryStr ? [queryStr] : undefined,
 80	      constraint: constraint?.toAPI(),
 81	    };
 82	    let cancelled = false;
 83	    const onResult = (newResult: Result) => {
 84	      if (!cancelled) dispatch(setResult(newResult));
 85	    };
 86	    const fetch =
 87	      search.searchType === SearchType.Goal
 88	        ? getGoalsGraph({ start, goals: [search.goal] })
 89	        : getNeighborsGraph({ start, depth: search.depth });
 90	    fetch
 91	      .then((response: api.Graph) => onResult({ graph: new korrel8r.Graph(response) }))
 92	      .catch((e: api.ApiError) => {
 93	        onResult({
 94	          title: e?.body?.error ? t('Korrel8r Error') : t('Request Failed'),
 95	          message: e?.body?.error || e.message || 'Unknown Error',
 96	        });
 97	      });
 98	    return () => {
 99	      cancelled = true;
100	      fetch.cancel();
101	    };
102	  }, [search, t, result, constraint, dispatch]);
103	
104	  const advancedToggleID = 'query-toggle';
105	  const advancedContentID = 'query-content';
106	
107	  // Dispatch a new search.
108	  // The SetSearch reducer clears result, triggering the fetch effect.
109	  const doSearch = React.useCallback((s: Search) => dispatch(setSearch(s)), [dispatch]);
110	
111	  return (
112	    <>
113	      <Stack>
114	        <Flex
115	          className="tp-plugin__panel-toolbar"
116	          direction={{ default: 'row' }}
117	          flexWrap={{ default: 'nowrap' }}
118	          alignItems={{ default: 'alignItemsCenter' }}
119	          spaceItems={{ default: 'spaceItemsXs' }}
120	        >
121	          <Tooltip
122	            content={
123	              locationQuery
124	                ? isFocused
125	                  ? t('Correlation graph is focused on the main view.')
126	                  : t('Focus the correlation on the main view.')
127	                : t('Current view does not allow correlation.')
128	            }
129	          >
130	            <Button
131	              className="tp-plugin__compact-control"
132	              isAriaDisabled={!locationQuery || isFocused}
133	              size="sm"
134	              onClick={() => {
135	                doSearch({
136	                  ...defaultSearch,
137	                  queryStr: locationQuery?.toString(),
138	                  period: search?.period,
139	                });
140	              }}
141	              icon={isFocused ? <LinkIcon /> : <UnlinkIcon />}
142	            >
143	              {t('Focus')}
144	            </Button>
145	          </Tooltip>
146	
147	          {/* Time range drop-down */}
148	          <Flex align={{ default: 'alignRight' }} spaceItems={{ default: 'spaceItemsNone' }}>
149	            <Tooltip content={t('Include data from this time range')}>
150	              <TimeRangeDropdown
151	                className="tp-plugin__compact-control"
152	                period={search.period ?? defaultSearch.period}
153	                onChange={(period: time.Period) => doSearch({ ...search, period })}
154	              />
155	            </Tooltip>
156	          </Flex>
157	
158	          {/* Right aligned buttons */}
159	          <Flex align={{ default: 'alignRight' }} spaceItems={{ default: 'spaceItemsNone' }}>
160	            {/* Advanced search toggle */}
161	            <Tooltip content={t('Advanced search parameters')}>
162	              <ExpandableSectionToggle
163	                contentId={advancedContentID}
164	                toggleId={advancedToggleID}
165	                isExpanded={showAdvanced}
166	                onToggle={(on: boolean) => setShowAdvanced(on)}
167	                aria-label={t('Advanced search parameters')}
168	              >
169	                <SlidersHIcon />
170	              </ExpandableSectionToggle>
171	            </Tooltip>
172	
173	            {/* Refresh button */}
174	            <Tooltip content={t('Refresh the graph by re-running the current search.')}>
175	              <Button
176	                variant="link"
177	                size="sm"
178	                isAriaDisabled={!search?.queryStr}
179	                onClick={() => doSearch(search)}
180	                aria-label={t('Refresh')}
181	                icon={<SyncIcon />}
182	              />
183	            </Tooltip>
184	          </Flex>
185	        </Flex>
186	
187	        <ExpandableSection
188	          className="tp-plugin__panel-query-container"
189	          contentId={advancedContentID}
190	          toggleId={advancedToggleID}
191	          isExpanded={showAdvanced}
192	          isDetached
193	        >
194	          <AdvancedSearchForm
195	            search={search}
196	            onSearch={doSearch}
197	            onCancel={() => setShowAdvanced(false)}
198	          />
199	        </ExpandableSection>
200	
201	        <Divider />
202	
203	        <StackItem className="tp-plugin__panel-topology-container" isFilled={true}>
204	          <Topology result={result} t={t} constraint={constraint} />
205	        </StackItem>
206	      </Stack>
207	    </>
208	  );
209	}
210	
211	interface TopologyProps {
212	  result?: Result;
213	  constraint?: korrel8r.Constraint;
214	  t: TFunction;
215	}
216	
217	const Topology: React.FC<TopologyProps> = ({ result, t, constraint }) => {
218	  const [loggingAvailable, loggingAvailableLoading] = usePluginAvailable('logging-view-plugin');
219	  const [netobserveAvailable, netobserveAvailableLoading] = usePluginAvailable('netobserv-plugin');
220	
221	  if (!result || loggingAvailableLoading || netobserveAvailableLoading) {
222	    // korrel8r query is loading or the plugin checks are loading
223	    return <Searching />;
224	  }
225	
226	  if (result?.graph?.nodes) {
227	    // Non-empty graph
228	    return (
229	      <Korrel8rTopology
230	        graph={result.graph}
231	        loggingAvailable={loggingAvailable}
232	        netobserveAvailable={netobserveAvailable}
233	        constraint={constraint}
234	      />
235	    );
236	  }
237	
238	  return (
239	    <TopologyInfoState
240	      titleText={result.title || t('No Correlated Signals Found')}
241	      // Only display fisrt 400 characters of error to prevent repeating errors
242	      text={result.message ? result.message.slice(0, 400) : t('Correlation result was empty.')}
243	      isError={result.isError}
244	    />
245	  );
246	};
247	
248	const Searching: React.FC = () => {
249	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
250	  return (
251	    <div className="tp-plugin__panel-topology-info">
252	      <EmptyState variant={EmptyStateVariant.sm} titleText={t('Searching')} headingLevel="h4" icon={Spinner}>
253	      </EmptyState>
254	    </div>
255	  );
256	};
257	
258	interface TopologyInfoStateProps {
259	  titleText: string;
260	  text: string;
261	  isError?: boolean;
262	}
263	
264	const TopologyInfoState: React.FC<TopologyInfoStateProps> = ({ titleText, text, isError }) => {
265	  return (
266	    <div className="tp-plugin__panel-topology-info">
267	      <EmptyState
268	        variant={EmptyStateVariant.sm}
269	        titleText={titleText}
270	        headingLevel="h4"
271	        icon={isError ? ExclamationCircleIcon : CubesIcon}
272	        status={isError ? 'danger' : undefined}
273	      >
274	        <EmptyStateBody>{text}</EmptyStateBody>
275	      </EmptyState>
276	    </div>
277	  );
278	};
